### src/popup.tsx

Source: https://github.com/better-auth/better-auth/blob/main/docs/content/docs/guides/browser-extension-guide.mdx

A quick example of using `authClient.useSession()` in a Plasmo popup component.

```tsx
import { authClient } from "./auth/auth-client"


function IndexPopup() {
    const {data, isPending, error} = authClient.useSession();
    if(isPending){
        return <>Loading...</>
    }
    if(error){
        return <>Error: {error.message}</>
    }
    if(data){
        return <>Signed in as {data.user.name}</>
    }
}

export default IndexPopup;
```

