### web/components/providers.tsx

Source: https://github.com/better-auth/better-auth/blob/main/docs/content/docs/integrations/electron.mdx

Example showing how to get and display the authorization code on the front-end after authentication completes.

```tsx
import { useEffect } from "react";
import { authClient } from "../auth-client";

function Providers({ children }) {
  useEffect(() => {
    const authorizationCode = authClient.electron.getAuthorizationCode();
    if (authorizationCode) {
      // Display the code to the user
      console.log("Authorization code:", authorizationCode);
    }
  }, []);

  return <>{children}</>;
}
```

